// Calculate pipeline metrics and WoW changes
const client = $('Filter: Has Forecast Sheet').first().json;
const pipelineData = $('Read Pipeline Data').all().map(i => i.json);
const lastWeekData = $('Read Last Week Snapshot').all().map(i => i.json);

// Aggregate by stage
const stages = {};
for (const deal of pipelineData) {
  const stage = deal['Stage'] || 'Unknown';
  if (!stages[stage]) stages[stage] = { count: 0, value: 0, deals: [] };
  stages[stage].count++;
  stages[stage].value += parseFloat(deal['Value'] || 0);
  stages[stage].deals.push(deal);
}

// Build pipeline summary
let pipelineSummary = 'Stage | Deal Count | Total Value\n';
let totalValue = 0;
for (const [stage, data] of Object.entries(stages)) {
  pipelineSummary += `${stage} | ${data.count} | $${data.value.toLocaleString()}\n`;
  totalValue += data.value;
}

// Simple WoW comparison
const lastWeekTotal = lastWeekData.reduce((sum, d) => sum + parseFloat(d['Value'] || 0), 0);
const wowChange = totalValue - lastWeekTotal;

const analysisDate = new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });

return [{
  json: {
    system_prompt: `You are an expert B2B SaaS revenue analyst working as a RevOps consultant. You analyze sales pipeline and forecast data to deliver sharp, actionable insights that help sales leaders make better decisions.\n\nYour analysis style:\n- Data-first: every claim backed by specific numbers\n- Pattern-aware: spot trends humans miss\n- Action-oriented: every insight ends with "so what" and "do what"\n- Calibrated confidence: distinguish between strong signals and weak ones\n- Executive-friendly: lead with the headline, details below`,
    user_prompt: `Analyze this client's pipeline and forecast data and generate an executive review.\n\n**Client:** ${client['Client Name']}\n**Analysis Date:** ${analysisDate}\n\n**Current Pipeline by Stage:**\n${pipelineSummary}\n**Total Pipeline:** $${totalValue.toLocaleString()}\n\n**Week-over-Week Change:** $${wowChange.toLocaleString()} (${wowChange >= 0 ? '+' : ''}${((wowChange / (lastWeekTotal || 1)) * 100).toFixed(1)}%)\n\n**Last Week Total Pipeline:** $${lastWeekTotal.toLocaleString()}\n\n---\n\nGenerate a comprehensive forecast review with: Executive Summary (3-5 sentences), Pipeline Health Scorecard (table with Coverage Ratio, Weighted Pipeline, Velocity, Conversion Rate, New Pipe Created — each rated green/yellow/red), Top 3 Insights (each with What, Why it matters, Recommended action), Deal-Level Alerts (at risk, accelerate, qualify out), Forecast Call (best/most likely/worst case with confidence), Recommended Actions (prioritized), and Positive Signals.`,
    model: 'opus',
    workflow_name: 'forecast-review',
    client_name: client['Client Name'],
    purpose: 'Forecast analysis',
    client: client,
    pipeline_data: pipelineData,
    total_value: totalValue
  }
}];
